import React from 'react';
import { useMenu } from '../hooks/useMenu';

/**
 * 사이드바 메뉴 컴포넌트
 * 
 * JSP의 sidebar.jsp와 비슷한 역할을 합니다.
 * - 메뉴 목록을 화면에 표시합니다
 * - 클릭하면 해당 메뉴로 이동합니다
 * 
 * Props:
 *   - activeMenu: 현재 활성화된 메뉴 ID (예: "dashboard")
 *   - onMenuClick: 메뉴 클릭 시 실행할 함수
 */
const Sidebar = ({ activeMenu, onMenuClick }) => {
    const { menus, loading } = useMenu();

    if (loading) {
        return (
            <div className="sidebar bg-dark text-white d-flex align-items-center justify-content-center" style={{ width: '250px', minHeight: '100vh' }}>
                <div className="spinner-border text-light" role="status">
                    <span className="visually-hidden">메뉴 로딩 중...</span>
                </div>
            </div>
        );
    }

    return (
        <div className="sidebar bg-dark text-white" style={{ width: '250px', minHeight: '100vh' }}>
            {/* 사이드바 헤더 */}
            <div className="p-3 border-bottom border-secondary">
                <h5 className="mb-0">
                    <i className="bi bi-shop me-2"></i>
                    관리자 메뉴
                </h5>
            </div>

            {/* 메뉴 목록 */}
            <nav className="nav flex-column p-2">
                {menus.map(menu => (
                    <a
                        key={menu.id}
                        href="#"
                        className={`nav-link text-white rounded mb-1 ${activeMenu === menu.id ? 'active bg-primary' : 'hover-bg-secondary'
                            }`}
                        onClick={(e) => {
                            e.preventDefault();
                            onMenuClick(menu.id);
                        }}
                        style={{
                            transition: 'all 0.2s',
                            padding: '0.75rem 1rem'
                        }}
                    >
                        <i className={`${menu.icon} me-2`}></i>
                        {menu.name}
                    </a>
                ))}
            </nav>

            {/* 사이드바 푸터 (선택사항) */}
            <div className="mt-auto p-3 border-top border-secondary text-center small text-muted">
                <i className="bi bi-info-circle me-1"></i>
                메뉴는 menuConfig.json에서 관리됩니다
            </div>
        </div>
    );
};

export default Sidebar;
